$(document).ready(async function() {
	$('#login-form-link').click(function(e) {
        $("#login-form").delay(100).fadeIn(100);
        $("#register-form").fadeOut(100);
        $("#recover-form").fadeOut(100); // Make sure to hide the recover form
        $('#register-form-link').removeClass('active');
        $('#recover-form-link').removeClass('active'); // Remove 'active' from recover-form-link
        $(this).addClass('active');
        e.preventDefault();
    });
    $('#register-form-link').click(function(e) {
        $("#register-form").delay(100).fadeIn(100);
        $("#login-form").fadeOut(100);
        $("#recover-form").fadeOut(100); // Make sure to hide the recover form
        $('#login-form-link').removeClass('active');
        $('#recover-form-link').removeClass('active'); // Remove 'active' from recover-form-link
        $(this).addClass('active');
        e.preventDefault();
    });
    $('#recover-form-link').click(function(e) {
        $("#recover-form").delay(100).fadeIn(100);
        $("#login-form").fadeOut(100);
        $("#register-form").fadeOut(100);
        $('#login-form-link').removeClass('active');
        $('#register-form-link').removeClass('active');
        $(this).addClass('active');
        e.preventDefault();
    });
	
    $('#recover-form').submit(async function(e) {
        e.preventDefault(); // Prevent the form from submitting in the traditional way
        await Recover(); // Call your Recover function here
    });
		
	$('#otp-submit').click(async function(e) {
        e.preventDefault(); // Prevent the form from submitting in the traditional way
        // Call your function for OTP submission here
        await otpSubmission(); 
    });

    // Handle final registration submission
    $('#finalreg-submit').click(async function(e) {
        e.preventDefault(); // Prevent the form from submitting in the traditional way
        // Call your function for final registration here
        await finalRegistrationSubmission(); 
    });
	
	$('#login-submit').click(async function(e) {
        e.preventDefault(); // Prevent the form from submitting in the traditional way
        // Call your function for final registration here
        await Login(); 
    });
	
	$.ajax({
        url: window.GIoTapiBaseUrl, // درخواست به ریشه API
        type: 'GET',		
		headers: {
			'Content-Type': 'application/json; charset=UTF-8',
            'Accept': 'application/json',
			'X-Requested-With': 'XMLHttpRequest'
        },
        dataType: 'json',
        success: function(data, status, xhr) {
            // 1. نمایش داده‌های دریافتی در کنسول
            console.log("AJAX Success: Received data:", data);
            console.log("AJAX Success: Status:", status); // وضعیت موفقیت (معمولاً "success")

            // 2. ادامه منطق قبلی برای نمایش در HTML
            // Construct the HTML string with the API data with icons - enhanced for RTL
            var displayHtml = '<div class="api-data">' +
                              '<p><i class="fas fa-shield-alt ml-2"></i><span class="api-data-label">جهت حفظ امنیت سامانه کلیه فعالیت های شما بر روی سامانه ثبت می گردد</span></p>' +
                              '<p><i class="fas fa-network-wired ml-2"></i><span class="api-data-label">آی پی اتصال شما به سرور:</span> ' + (data.ClientIP || 'N/A') + '</p>' + // اضافه کردن بررسی وجود پراپرتی
                              '<p><i class="fas fa-globe ml-2"></i><span class="api-data-label">مبدا درخواست:</span> ' + (data.ClientCountry || 'N/A') + '</p>' +
                              '<p><i class="fas fa-clock ml-2"></i><span class="api-data-label">زمان بین المللی گرینویچ:</span> ' + (data.GMTime || 'N/A') + '</p>' +
                              '</div>';

            // Append the information to the specified container
            $('#apiDataDisplay').html(displayHtml);
        },

        error: function(xhr, status, error) {
            // 1. نمایش جزئیات خطا در کنسول
            console.error("--- AJAX Error Details ---");
            console.error("Status Code:", xhr.status);                  // کد وضعیت HTTP (مثلاً 404, 500, 502)
            console.error("Status Text (jQuery):", status);             // متن وضعیت از jQuery (مانند "error", "timeout")
            console.error("Error Thrown:", error);                      // متن خطای HTTP یا Exception
            console.error("Response Text (Raw):", xhr.responseText);    // متن کامل پاسخ دریافتی از سرور (بسیار مهم برای دیباگ 5xx)
            console.error("Full XHR Object:", xhr);                     // نمایش کل آبجکت XHR برای بررسی‌های بیشتر
            console.error("--- End AJAX Error Details ---");


            // 2. نمایش پیام خطا به کاربر (می‌توانید کد وضعیت را هم اضافه کنید)
            $('#apiDataDisplay').html('<p style="color: red;">خطا در برقراری ارتباط با سرور! (کد: ' + xhr.status + ')</p>');
        }
    });
});

function toggleLoginPasswordVisibility() {
    var passwordInput = document.getElementById('password_login');
    var toggleButton = document.getElementById('toggleLoginPassword');
    if (passwordInput.type === 'password') {
        passwordInput.type = 'text';
        toggleButton.innerHTML = '<i class="fas fa-eye-slash"></i>'; // Change to eye-slash icon
    } else {
        passwordInput.type = 'password';
        toggleButton.innerHTML = '<i class="fas fa-eye"></i>'; // Change back to eye icon
    }
}

