async function Recover()	{
	// Add your logic to submit to your backend server here.
	showNotification("بازیابی رمز عبور", "OK") ;
	var _userid = document.getElementById('codemelli_recovery').value.trim() ;
	var _phonenumber = document.getElementById('phonenumber_recovery').value.trim() ;
	if ( !_userid || !isValidNationalCode(_userid) ) {
		showNotification("لطفا کد ملی خود را به طور صحیح وارد نمائید.", "Alarm") ;
		return;
	}
	if (!_phonenumber || !isValidPhoneNumber(_phonenumber) )	{
		showNotification("لطفا شماره تلفن همراه خود را به درستی بدون +98 در ابتدای آن وارد نمائید.", "Alarm") ; 
		return;
	}
	var data = {
    	userid: _userid,
    	number: _phonenumber
    };
	// Assuming postData returns a promise and '/authenticate' is the correct endpoint
	try{
		const result = await postData(data, '/passwordrecovery');
    	// Assuming result is the JSON object directly (not a string)
    	// If result is a string, use JSON.parse(result) to convert it to an object
        // Check if result is a string and try to parse it
        if (typeof result === 'string') {
            try {
                var resultstr = JSON.parse(result);
            } catch (e) {
                console.error('Parsing error:', e);
                showNotification("خطا در پردازش پاسخ سرور", "Alarm");
                return;
            }
        }
    	// Check if the result contains the session key
    	if (result && result.status) {
			if(result.status === 'success')	{			
				console.log('Password successfully sent to you via SMS');
				showNotification("رمز عبور جدید با موفقیت برای شما پیامک شد", "OK") ;
			}else {
				// Construct an error message from the JSON response
				let errorMessage = "خطا در ارسال رمزعبور جدید:\n";
				for (let key in result) {
					if (result.hasOwnProperty(key)) {
						errorMessage += `${key}: ${result[key]}\n`;
					}
				}
				showNotification(errorMessage, "Alarm");
			}
    	} else {
    		console.log('Error sending new password to you by SMS');
    		showNotification("خطا در ارسال رمزعبور جدید", "Alarm") ;
    	}
    }catch(error) {
    	console.log('Login request failed:', error);
    	showNotification("خطا در برقراری ارتباط با سرور ...", "Alarm") ;
    };
	
}

async function Login()	{
  // Add your logic to submit to your backend server here.
    var _username = document.getElementById('username_login').value.trim() ;
    var _password = document.getElementById('password_login').value.trim() ;
    if ( !_username || !_password ) {
    	showNotification("لطفا نام کاربری و رمز عبور خود را به درستی وارد نمائید", "Alarm") ;
    	return;
    }    
	var _SHA256password = await sha256(_password);	
    var data = {
    	username: _username,
    	password: _SHA256password
    };
        
    // Assuming postData returns a promise and '/authenticate' is the correct endpoint
    try{
		const result = await postData(data, '/authenticate');
    	// Assuming result is the JSON object directly (not a string)
    	// If result is a string, use JSON.parse(result) to convert it to an object
        // Check if result is a string and try to parse it
        if (typeof result === 'string') {
            try {
                var resultstr = JSON.parse(result);
            } catch (e) {
                console.error('Parsing error:', e);
                showNotification("خطا در پردازش پاسخ سرور", "Alarm");
                return;
            }
        }
    	// Check if the result contains the session key
    	if (result && result.status) {
			if(result.status === 'success')	{
    		// Store the JWT and userid in Local Storage
				sessionStorage.setItem('session', result.session);
				sessionStorage.setItem('userid', result.userid);
				sessionStorage.setItem('billcharge', result.billcharge);
				sessionStorage.setItem('familyname', result.familyname);
				sessionStorage.setItem('mqttenable', result.mqttenable);
				sessionStorage.setItem('logintime', result.logintime);
				sessionStorage.setItem('mqttvalidtime', result.mqttvalidtime);
				sessionStorage.setItem('shortname', result.shortname);
				sessionStorage.setItem('status', result.status);
				sessionStorage.setItem('userid', result.userid);
				sessionStorage.setItem('mqtttopic', result.mqtttopic);
				sessionStorage.setItem('mqttsendtopic', result.mqttsendtopic);
				sessionStorage.setItem('mqttrecvtopic', result.mqttrecvtopic);
				sessionStorage.setItem('mqttchattopic', result.mqttchattopic);
				sessionStorage.setItem('mqttuser', result.mqttuser);
				sessionStorage.setItem('mqttpass', result.mqttpass);
			
				console.log('Login successful. JWT and userid stored in Local Storage.');
				showNotification("ورود به سیستم با موفقیت انجام شد", "OK") ;
				window.location.href = 'https://my.giot.ir/dashboard/index.html';
			}else {
				        // Construct an error message from the JSON response
				let errorMessage = "خطا در ورود به سامانه:\n";
				for (let key in result) {
					if (result.hasOwnProperty(key)) {
						errorMessage += `${key}: ${result[key]}\n`;
					}
				}
				showNotification(errorMessage, "Alarm");
			}
    	} else {
    		console.log('Login failed or the response is not in the expected format.');
    		showNotification("نام کاربری یا رمز عبور اشتباه است", "Alarm") ;
    	}
    }catch(error) {
    	console.log('Login request failed:', error);
    	showNotification("خطا در برقراری ارتباط با سرور ...", "Alarm") ;
    };

}

async function otpSubmission() {
    // Your OTP submission function's code here.
    // Example: console.log("OTP Submit button clicked.");
              // Add your logic to submit to your backend server here.
			  var _phonenumber = document.getElementById('phonenumber_register').value ;
			  _phonenumber = String(_phonenumber).trim();
			  if (!_phonenumber || !isValidPhoneNumber(_phonenumber) )	{
				showNotification("لطفا شماره تلفن همراه خود را به درستی بدون +98 در ابتدای آن وارد نمائید.", "Alarm") ; 
			  }else	{
				showNotification("درخواست کد احراز هویت پیامکی"+_phonenumber, "OK") ;
				var data = {
					number: _phonenumber
				};
					
				// Assuming postData returns a promise and '/authenticate' is the correct endpoint
				try{
					const result = await postData(data, '/SendOTPsms');
					// Assuming result is the JSON object directly (not a string)
					// If result is a string, use JSON.parse(result) to convert it to an object
					// Check if result is a string and try to parse it
					if (typeof result === 'string') {
						try {
							var resultstr = JSON.parse(result);
						} catch (e) {
							console.error('Parsing error:', e);
							showNotification("خطا در پردازش پاسخ سرور", "Alarm");
							return;
						}
					}
					// Check if the result contains the session key
					if (result && result.status) {
						if( result.status === 'success')	{
							// Store the JWT and userid in Local Storage
							EnableRegisterForm() ;
							console.log('کد یک بار مصرف پیامکی ارسال شد.');
							showNotification("کد یک بار مصرف پیامکی ارسال شد.", "OK") ;
						}else if( result.status === 'warn')	{
							EnableRegisterForm() ;
							console.log('کد یکبار مصرف قبلی شما هنوز اعتبار دارد لطفا از همان استفاده کنید.');
							showNotification("کد یکبار مصرف قبلی شما هنوز اعتبار دارد لطفا از همان استفاده کنید.", "OK") ;
						}else	{
							// Construct an error message from the JSON response
							let errorMessage = "خطا در ارسال کد یک بار مصرف پیامکی:\n";
							for (let key in result) {
								if (result.hasOwnProperty(key)) {
									errorMessage += `${key}: ${result[key]}\n`;
								}
							}
							showNotification(errorMessage, "Alarm");
						}
					} else {
						console.log('دریافت پاسخ خطا از سرور' + result );
						showNotification("دریافت پاسخ خطا از سرور" + result, "Alarm") ;
					}
				}catch(error) {
					console.log('Login request failed:', error);
					showNotification("خطا در برقراری ارتباط با سرور ...", "Alarm") ;
				};
			  }
	
}

async function finalRegistrationSubmission() {
    // Your Final Registration submission function's code here.
    // Example: console.log("Final Registration Submit button clicked.");
            // Add your logic to submit to your backend server here.
			showNotification("مرحله پایانی ثبت نام" , "OK") ;
			var _phonenumber = document.getElementById('phonenumber_register').value.trim() ;
			
			var _codemelli = document.getElementById('codemelli_register').value.trim() ;
			if (!_codemelli || !isValidNationalCode(_codemelli) )	{
				showNotification("لطفا کد ملی خود را به درستی وارد نمائید\nو کد ملی متناظر با سیمکارت ثبت شده را وارد نمائید", "Alarm") ; 
				return ;
			}
			
			var _email_register = document.getElementById('email_register').value.trim() ;
			if (!_email_register || !isValidEmail(_email_register) )	{
				showNotification("لطفا ایمیل خود را به درستی وارد نمائید", "Alarm") ; 
				return ;
			}
			
			var _familyname_register = document.getElementById('familyname_register').value.trim() ;
			if ( !_familyname_register )	{
				showNotification("فیلد نام خانوادگی خالی می باشد.", "Alarm") ; 
				return ;
			}
			
			var _shortname_register = document.getElementById('shortname_register').value.trim() ;
			if ( !_shortname_register )	{
				showNotification("فیلد نام خالی می باشد.", "Alarm") ; 
				return ;
			}
			
			var _password_register1 = document.getElementById('password_register1').value.trim() ;
			var _password_register2 = document.getElementById('password_register2').value.trim() ;
			if (!_password_register1) {
				showNotification("پسورد نمی تواند خالی باشد", "Alarm");
				return;
			}
			if (_password_register1 !== _password_register2) {
				showNotification("پسورد ها همخوانی ندارند", "Alarm");
				return;
			}
			
			var _city_register = document.getElementById('city_register').value.trim() ;
			if ( !_city_register )	{
				showNotification("لطفا نام شهر محل سکونت را وارد نمائید.", "Alarm") ; 
				return ;
			}
			
			var _provience_register = document.getElementById('provience_register').value.trim() ;
			if ( !_provience_register )	{
				showNotification("لطفا استان محل سکونت خود را وارد نمائید", "Alarm") ; 
				return ;
			}
			
			var _address_register = document.getElementById('address_register').value.trim() ;
			if ( !_address_register )	{
				showNotification("لطفا آدرس پستی خود را وارد نمائید.", "Alarm") ; 
				return ;
			}
			
			var _codeposti_register = document.getElementById('codeposti_register').value.trim() ;
			if ( !_codeposti_register )	{
				showNotification("لطفا کد پستی 10 رقمی خود را وارد نمائید.", "Alarm") ; 
				return ;
			}
			
			var _otpcode = document.getElementById('otpcode').value.trim() ;
			if ( !_otpcode )	{
				showNotification("لطفا کد یک بار مصرف دریافتی را وارد کنید.", "Alarm") ; 
				return ;
			}
			
			var _password_sha256 = await sha256(_password_register1) ;		
			var data = {
				number: _phonenumber,
				codemelli: _codemelli,
				emailaddr: _email_register,
				password: _password_sha256,
				shortname: _shortname_register,
				familyname: _familyname_register,
				shahr: _city_register,
				ostan: _provience_register,
				address: _address_register,
				postcode: _codeposti_register,
				otpstr: _otpcode
			};
			
			// نمایش وضعیت ارسال به کاربر
			showNotification("در حال ارسال اطلاعات به سرور...", "OK");
			
			// استفاده از تابع postData با قابلیت retry
			try{
				// تلاش برای ارسال داده با 3 بار retry در صورت خطا
				const result = await postData(data, '/registeruser', 3, 1000);
				
				// بررسی نوع داده برگشتی
				if (typeof result === 'string') {
					try {
						var resultstr = JSON.parse(result);
					} catch (e) {
						console.error('Parsing error:', e);
						showNotification("خطا در پردازش پاسخ سرور", "Alarm");
						return;
					}
				}
				// Check if the result contains the session key
				if (result && result.status) {
					if( result.status === 'success')	{
						// Store the JWT and userid in Local Storage
						PurgeRegisterForm() ;
						console.log('کاربر با موفقیت ثبت شد.');
						showNotification("کاربر با موفقیت ثبت شد.", "OK") ;
					}else if( result.status === 'warn')	{
						console.log('کد یک بار مصرف از آی پی دیگری درخواست شده که با آی پی شما همخوانی ندارد');
						showNotification("کد یک بار مصرف از آی پی دیگری درخواست شده که با آی پی شما همخوانی ندارد", "OK") ;
					}else	{
						// Construct an error message from the JSON response
						let errorMessage = "خطا در ثبت نام کاربر:\n";
						for (let key in result) {
							if (result.hasOwnProperty(key)) {
								errorMessage += `${key}: ${result[key]}\n`;
							}
						}
						showNotification(errorMessage, "Alarm");
					}
				} else {
					console.log('دریافت پاسخ خطا از سرور' + result );
					showNotification("دریافت پاسخ خطا از سرور" + result, "Alarm") ;
				}
			}catch(error) {
				console.log('Registration request failed:', error);
				showNotification("خطا در برقراری ارتباط با سرور. لطفاً مجدداً تلاش کنید.", "Alarm") ;
			};
	
}

$('#enableButton').click(function() {
    $('#otpcode').prop('disabled', false);
});

function showNotification(message, alarmtype) {
    var bgColor = "#d4edda" ;
	if (alarmtype === 'OK') {
		bgColor = "#d4edda" ;
		$('#OKnotificationSound')[0].play();
	}else	{
		bgColor = "#f8d7da" ;
		$('#AlarmnotificationSound')[0].play();
	}
	$('#notification').text(message)
                     .css('background', bgColor) // Set background color dynamically
                     .fadeIn()
                     .delay(3000)
                     .fadeOut('slow');
}

async function sha256(text) {
    // Encode input string as UTF-8
    const msgBuffer = new TextEncoder().encode(text); 
    
    // Hash the message
    const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
    
    // Convert ArrayBuffer to Array
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    
    // Convert bytes to hex string
    const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    return hashHex;
}

function isValidPhoneNumber(str) {
    return /^09\d{9}$/.test(str);
}

function EnableRegisterForm() {
	document.getElementById('otp-submit').disabled = true;
	document.getElementById('phonenumber_register').disabled = true;
	
	document.getElementById('otpcode').disabled = false;
	document.getElementById('familyname_register').disabled = false;
	document.getElementById('shortname_register').disabled = false;
	document.getElementById('codemelli_register').disabled = false;
	document.getElementById('email_register').disabled = false;
	document.getElementById('password_register2').disabled = false;
	document.getElementById('password_register1').disabled = false;
	document.getElementById('city_register').disabled = false;
	document.getElementById('provience_register').disabled = false;
	document.getElementById('address_register').disabled = false;
	document.getElementById('codeposti_register').disabled = false;
	document.getElementById('finalreg-submit').disabled = false;
}

function PurgeRegisterForm() {
	document.getElementById('otp-submit').disabled = false;
	document.getElementById('phonenumber_register').value = '' ;
	document.getElementById('phonenumber_register').disabled = false;
	
	document.getElementById('otpcode').value = '';
	document.getElementById('otpcode').disabled = true;
	document.getElementById('familyname_register').value = '';
	document.getElementById('familyname_register').disabled = true;
	document.getElementById('shortname_register').value = '';
	document.getElementById('shortname_register').disabled = true;
	document.getElementById('codemelli_register').value = '';
	document.getElementById('codemelli_register').disabled = true;
	document.getElementById('email_register').value = '';
	document.getElementById('email_register').disabled = true;
	document.getElementById('password_register2').value = '';
	document.getElementById('password_register2').disabled = true;
	document.getElementById('password_register1').value = '';
	document.getElementById('password_register1').disabled = true;
	document.getElementById('city_register').value = '';
	document.getElementById('city_register').disabled = true;
	document.getElementById('provience_register').value = '';
	document.getElementById('provience_register').disabled = true;
	document.getElementById('address_register').value = '';
	document.getElementById('address_register').disabled = true;
	document.getElementById('codeposti_register').value = '';
	document.getElementById('codeposti_register').disabled = true;
	document.getElementById('finalreg-submit').disabled = true;
}

function isValidNationalCode(nationalCode) {
  // اضافه کردن صفر به سمت چپ در صورت نیاز
  while (nationalCode.length < 10) {
    nationalCode = "0" + nationalCode;
  }

  const digits = nationalCode.split('').map(Number);
  const sum = digits.slice(0, 9).reduce((acc, val, idx) => acc + val * (10 - idx), 0);
  const remainder = sum % 11;
  const controlDigit = remainder < 2 ? remainder : 11 - remainder;

  return controlDigit === digits[9];
}

function isValidEmail(email) {
    const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return regex.test(email);
}